// Import necessary modules
const Mod = require('mod');
const World = require('world');

class HarvestHubMod extends Mod {
  constructor() {
    super({
      id: 'harvest_hub',
      version: '1.0.0'
    });
  }

  init() {
    // Define a new biome for the mod
    this.defineBiome();

    // Define a new mob for the mod
    this.defineMob();

    // Add recipes for the mod
    this.addRecipes();
  }

  defineBiome() {
    const biome = World.Biomes.createCustom({
      name: 'Harvest Hub Biome',
      temperature: 0.5,
      rainfall: 0.5,
      humidity: 0.5,
      spawnGroup: ['CREATURES', 'MONSTERS'],
      structures: ['BASTION_REEF'],
      flowerTypes: ['FLOWER_PINK']
    });
    biome.save();
  }

  defineMob() {
    const mob = World.Mobs.createCustom({
      id: 'harvest_hub_mob',
      classification: 'CREATURES',
      aiTasks: ['AI_TASK_WALK_FORWARD', 'AI_TASK_JUMP'],
      behaviors: [
        { type: 'ATTACK_NEARBY', chance: 0.5 }
      ]
    });
    mob.save();
  }

  addRecipes() {
    const recipe = World.Recipes.createShapeless({
      id: 'harvest_hub_recipe',
      inputs: ['COAL_ORE'],
      output: ['GOLD_INGOT']
    });
