function generateProceduralChunk(chunkX, chunkZ) {
    // Example: Generate a simple geological formation with mountains
    const data = [
        { x: -64, y: 0, z: -64 },
        { x: 64, y: 0, z: -64 },
        { x: -64, y: 128, z: -64 },
        { x: 64, y: 128, z: -64 }
    ];

    // Fill the chunk with dirt and stone
    data.forEach(block => {
        const blockX = Math.floor((block.x + chunkX) * 32);
        const blockY = Math.floor(block.y);
        const blockZ = Math.floor((block.z + chunkZ) * 32);

        // Place dirt at the bottom
        server.setBlock(blockX, blockY, blockZ, "minecraft:dirt");
        // Place stone on top
        server.setBlock(blockX, blockY + 1, blockZ, "minecraft:stone");
    });
}

// Event listener for chunk generation
server.on('chunk_data', (event) => {
    const { chunkX, chunkZ } = event;
    generateProceduralChunk(chunkX, chunkZ);
});

// Register the mod to the server
server.registerMod(MOD_NAME, MOD_VERSION);
