const { MinecraftServer, ItemTypes, ItemStack } = require('@minecraft/server');

let equippedDiscs = {};

function equipDisc(event) {
  const player = event.player;
  const newDiscId = event.item.id;

  if (!equippedDiscs[player.name]) {
    equippedDiscs[player.name] = [];
  }

  // Remove the old disc from the equipment list
  equippedDiscs[player.name].forEach((disc, index) => {
    if (disc.id === event.item.id) {
      equippedDiscs[player.name].splice(index, 1);
    }
  });

  // Add the new disc to the equipment list
  equippedDiscs[player.name].push({
    id: newDiscId,
