    public static final DeferredRegister<Item> ITEMS = DeferredRegister.create(ForgeRegistries.ITEMS, "mod");

    // Registering blocks
    public static final RegistryObject<ModBlock> MOD_BLOCK = BLOCKS.register("mod_block", () -> new ModBlock(Properties.of(Material.METAL).sound(SoundType.METAL)));

    // Registering items
    public static final RegistryObject<Item> MOD_ITEM = ITEMS.register("mod_item", () -> new BlockItem(MOD_BLOCK.get(), new Item.Properties()));

    @SubscribeEvent
    public static void onBlocksRegistry(final RegistryEvent.Register<Block> event) {
        event.getRegistry().registerAll(BLOCKS.getEntries());
    }

    @SubscribeEvent
    public static void onItemsRegistry(final RegistryEvent.Register<Item> event) {
        event.getRegistry().registerAll(ITEMS.getEntries());
    }
}
