// Define the PackHub class
class PackHub {
  constructor() {
    this.storage = {};
  }

  // Function to add items to storage
  addItemToStorage(player, itemId) {
    if (!this.storage[player]) {
      this.storage[player] = new Array();
    }
    this.storage[player].push(itemId);
  }

  // Function to get all items from storage
  getAllItemsFromStorage(player) {
    return this.storage[player];
  }
}

// Create an instance of PackHub
const packHub = new PackHub();

// Define the onUse event for containers
function onUse(event) {
  const player = event.player;
  const itemId = event.blockId;

  // Add item to storage when a container is used
  packHub.addItemToStorage(player, itemId);
}

// Register the onUse event
BedrockScript.on('onUse', onUse);

// Define the onTick event for managing cargo
function onTick(event) {
  const player = event.player;
  const items = packHub.getAllItemsFromStorage(player);

  // Automatically organize inventory based on efficiency points
  items.sort((a, b) => a - b);
}

// Register the onTick event
BedrockScript.on('onTick', onTick);
