import net.minecraft.item.ItemGroup;
import net.minecraftforge.eventbus.api.IEventBus;
import net.minecraftforge.fml.common.Mod;
import net.minecraftforge.fml.javafmlmod.FMLJavaModLoadingContext;

@Mod("example_mod")
public class ExampleMod {

    public ExampleMod() {
        IEventBus eventBus = FMLJavaModLoadingContext.get().getModEventBus();

        // Registering the mod with Forge's event bus
        eventBus.addListener(this::setup);

        ItemGroup.CREATIVE_MODE_TAB.register(() -> new ItemGroup("example_mod") {
            @Override
            public String getName() {
                return "Example Mod";
            }

            @Override
            public ItemStack createIcon() {
                // You can define an icon item here if desired
                return ItemStack.EMPTY;
            }
        });
    }

    private void setup( FMLCommonSetupEvent event) {
        // This method will be called when the mod is initialized during startup.
        // Here, you can add any logic that needs to run on server-side initialization.

        System.out.println("Example Mod has been loaded!");
    }
}
```

