// Import necessary modules and define global variables
import { world, events } from "@minecraft/server";

// Main function to initialize the mod
function organixInit() {
    // Register blocks and items
    createBlocks();
    createItems();

    // Set up event listeners for interactions
    setupInteractions();

    // Load recipes
    loadRecipes();
}

// Function to register blocks and items
function createBlocks() {
    const chestBlock = block.create('organix_chest', { texture: 'chest' });
    chestBlock.register();

    const modularStorageBlock = block.create('organix_modular_storage', { texture: 'modular_storage_block' });
    modularStorageBlock.register();
}

function createItems() {
    const organixItem = item.create('organix_item');
    organixItem.texture = 'organix_item';
    organixItem.register();

    const secretCompartmentBlock = block.create('organix_secret_compartment', { texture: 'secret_compartment' });
    secretCompartmentBlock.register();
}

// Function to handle block interactions
function setupInteractions() {
    events.beforePlayerUseItem.subscribe((event) => {
        if (event.item.id === 'organix_item') {
            // Implement item interaction logic here
            world.sendMessage("Organix item used!");
        }
    });

    events.serverTick.subscribe(() => {
        // Implement server tick logic here, e.g., auto-sorting items
        world.sendMessage("Server tick called!");
    });
}

// Function to load recipes
function loadRecipes() {
    const recipeManager = world.getRegistry(Registry.Recipes);
    const jsonPath = '/organix/recipes.json';
    const recipesData = fs.readFileSync(jsonPath, 'utf8');
    const recipesArray = JSON.parse(recipesData);

    recipesArray.forEach((recipe) => {
        recipeManager.add(recipe.type, (context) => {
            // Implement recipe logic here
            context.player.sendMessage(`Recipe processed!`);
        });
    });
}

// Call the main initialization function when the mod is loaded
