const { Server } = require("@minecraft/server");
const { Block, MinecraftBlockTypes } = require("@minecraft/block");

// Initialize the server and register a command to spawn tunnels
Server.events.beforeChat.subscribe((event) => {
    if (event.message.toLowerCase() === "/spawntunnel") {
        const player = event.sender;
        const location = player.location;

        // Create tunnel blocks around the player's position
        for (let x = -5; x <= 5; x++) {
            for (let z = -5; z <= 5; z++) {
                const blockPos = new BlockPosition(location.x + x, location.y, location.z + z);
                const tunnelBlock = MinecraftBlockTypes.subterranean_stone.create(blockPos);

                // Set the block's state to a specific value if needed
                tunnelBlock.state.set("subtunnel_type", "standard");

                // Place the block in the world
                Server.world.setBlock(tunnelBlock.position, tunnelBlock);
            }
        }

        player.sendMessage("Tunnels spawned!");
    }
});

// Define a custom block for tunnels
Server.createBlock({
    name: "subterranean_stone",
    blockType: MinecraftBlockTypes.stone,
    states: {
        subtunnel_type: ["standard", "secret"]
    },
    behaviors: [
        {
            type: "interact",
            action: (block, player) => {
                // Handle tunnel interaction logic
                console.log("Tunnel interacted with by:", player.name);
            }
        }
    ]
});
