   public void onCraftTableUse(CraftTableItemEvent event) {
       if (event.getIngredientCount() >= 2) {
           ItemStack output = new ItemStack(Registry.ITEM.get(new Identifier("harvest_harmony", "dinner_meal")));
           event.setRecipeOutput(output);
       }
